import base64
import json

def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        data = json.loads(decoded.decode('utf-8'))
        if data.get('valid'):
            return data.get('data')
        return None
    except (base64.binascii.Error, json.JSONDecodeError):
        return None
